---

## API Route Implementation

**File**: `src/app/api/agents/v1/route.ts`

```typescript
export const POST = observe(async (req: NextRequest) => {
  // 1. Authenticate user
  const { id: userId } = await authenticateUser(requestId);

  // 2. Extract request body
  const { message, id: projectId, chatId, globalSystemInstructions } = await req.json();

  // 3. Verify project ownership
  const project = await findProjectByIdForUser({ projectId, userId });

  // 4. Resolve or create chat
  let chat = await getChatById({ chatId, userId });
  if (!chat) {
    chat = await createChat({ id: chatId, projectId, userId, title: "New Chat" });
  }

  // 5. Load previous messages
  const previousMessages = await loadChatMessages(chat.id, userId);

  // 6. Build messages array
  let messages = [...previousMessages, message];

  // 7. Validate messages against tool schemas
  const validatedMessages = await validateUIMessages({
    messages,
    tools: superAgentTools,  // Important: validates against super agent tools
  });

  // 8. Save user message
  if (message.role === "user") {
    await saveChatMessage({ message, chatId: chat.id, userId });
  }

  // 9. Return streaming response
  return await createAgentUIStreamResponse({
    agent: superAgent,  // Always uses super agent
    uiMessages: validatedMessages,
    onFinish: async ({ responseMessage }) => {
      // Save assistant message
      await saveChatMessage({ message: responseMessage, chatId: chat.id, userId });
    },
  });
});
```

**Key Points**:
- Always uses `superAgent` (never calls subagents directly)
- Validates messages against `superAgentTools`
- Saves messages to PostgreSQL via `saveChatMessage`
- Uses Langfuse for tracing

---

## Client-Side Implementation

### ChatClient.tsx

```typescript
const { messages, sendMessage, status, setMessages, stop } = useChat({
  id: projectId,
  transport: new DefaultChatTransport({
    api: "/api/agents/v1",
    body: () => ({
      globalSystemInstructions,
      chatId: activeChatIdRef.current,
      selection: selectionRef.current,
    }),
  }),
  sendAutomaticallyWhen: lastAssistantMessageIsCompleteWithToolCalls,
  onFinish({ message }) {
    // Refresh credits
    refreshCredits();

    // Extract media from tool outputs
    for (const part of message.parts) {
      if (part.type.startsWith("tool-") && part.state === "output-available") {
        // Extract images/videos and add to canvas
        const media = extractMediaUrls(part.output);
        if (media) {
          executeCommand({ type: "add", url: media.urls[0], mediaType: media.type });
        }
      }
    }
  },
});
```

**Key Features**:
- `sendAutomaticallyWhen`: Enables multi-step tool execution
- `onFinish`: Adds generated media to canvas
- Uses refs for fresh values in transport callbacks

