  // Show status (Preparing â†’ Processing â†’ Completed)
  const message = getSimpleToolMessage(part.type, part.state);

  // Show credits deducted (for media tools)
  const showCredits = part.output?.totalCredits !== undefined;

  return (
    <>
      <MessageContent>{message}</MessageContent>
