  model: anthropic("claude-haiku-4-5"),
  tools: {
    writeFile,
    readFile,
    runTests,
  },
  instructions: `You are a coding specialist...`,
});

export const codeSubagentTool = tool({
  description: 'Write, edit, or test code',
  inputSchema: z.object({
    task: z.string(),
  }),
  execute: async function* ({ task }, { abortSignal }) {
    const result = await codeAgent.stream({ prompt: task, abortSignal });
    for await (const message of readUIMessageStream({ stream: result.toUIMessageStream() })) {
      yield message;
    }
  },
  toModelOutput: ({ output: message }) => {
    const lastTextPart = message?.parts.findLast(p => p.type === 'text');
