    writeFile,
    readFile,
    runTests,
  },
  instructions: `You are a coding specialist...`,
});

export const codeSubagentTool = tool({
  description: 'Write, edit, or test code',
  inputSchema: z.object({
    task: z.string(),
  }),
  execute: async function* ({ task }, { abortSignal }) {
    const result = await codeAgent.stream({ prompt: task, abortSignal });
    for await (const message of readUIMessageStream({ stream: result.toUIMessageStream() })) {
      yield message;
    }
  },
  toModelOutput: ({ output: message }) => {
    const lastTextPart = message?.parts.findLast(p => p.type === 'text');
    return { type: 'text', value: lastTextPart?.text ?? 'Code task completed.' };
  },
});
```

### 2. Add to super agent

```typescript
// src/lib/agents/master-agents.ts
export const superAgentTools = {
  mediaGeneration: mediaSubagentTool,
  research: researchSubagentTool,
  coding: codeSubagentTool,  // â†گ Add here
};

export const superAgent = new ToolLoopAgent({
  // ... existing config
  instructions: `...
- coding: For writing, editing, or testing code.
  `,
});
```

### 3. Add UI rendering

```typescript
// src/components/product/editor/agent/MessagePartRenderer.tsx
case "tool-coding":
  return renderSubagentIndicator(part, index);
```

### 4. Add metadata

```typescript
// src/components/product/editor/agent/constants.ts
export const SUBAGENT_META = {
  "tool-mediaGeneration": { icon: "ًںژ¨", name: "Media Agent" },
  "tool-research": { icon: "ًں”چ", name: "Research Agent" },
  "tool-coding": { icon: "ًں’»", name: "Code Agent" },  // â†گ Add here
};
```

---

## Known Patterns

### 1. Sequential Subagent Calls

Super agent can call subagents in sequence:

```
User: Research AI trends and create an image summarizing them

Flow:
1. Super agent calls research tool
2. Research agent searches web
3. Returns findings to super agent
4. Super agent calls mediaGeneration tool
5. Media agent creates image
6. Returns result to super agent
7. Super agent responds with complete answer
```

### 2. Parallel Subagent Calls

Currently sequential, but can be parallelized:

```typescript
// Future enhancement
const [researchResult, mediaResult] = await Promise.all([
  researchSubagent.generate({ prompt: researchTask }),
  mediaAgent.generate({ prompt: mediaTask }),
]);
```

### 3. Nested Tools

Subagents can have many tools:
- Media agent has 15+ tools
- Each tool is specialized (generateImage, generateVideo, etc.)
- Subagent routes to correct tool

---

## Debugging

### Enable Debug Logs

```typescript
// In MessagePartRenderer.tsx
console.log("[DEBUG] parts:", JSON.stringify(parts, null, 2));

// In route.ts
logger.info(`Messages: ${JSON.stringify(messages, null, 2)}`);
```

### Check Tool Call IDs

```typescript
// In onFinish callback
console.log("Tool calls:", message.parts.filter(p => p.type.startsWith("tool-")));
```

### Verify Subagent Execution

```typescript
// In mediaSubagentTool execute
console.log("Subagent task:", task);
console.log("Subagent result:", result.text);
```

---

## Performance Considerations

### 1. Model Selection
- **Super Agent**: Sonnet 4.5 (better routing, ~2x cost)
- **Subagents**: Haiku 4.5 (faster, cheaper)

### 2. Token Usage
- Super agent sees only summaries
- Full subagent context isolated
- Conversation history stays manageable

### 3. Streaming
- All subagents stream progress
- UI updates in real-time
- Better UX for long operations

---

## Security Notes

### 1. Context Isolation
- Subagents don't inherit main conversation
- Each invocation starts fresh
- Prevents context pollution

### 2. Tool Access Control
- Each agent only has tools it needs
- Media agent can't search web
- Research agent can't generate media

### 3. User Authentication
- All requests authenticated at route level
- Project ownership verified
- Chat access controlled

---

## Future Enhancements

### 1. Dynamic Tool Loading
- Load tools based on user plan
- Enable/disable subagents per user

### 2. Subagent Composition
- Subagents calling other subagents
- Deeper hierarchy if needed

### 3. Parallel Execution
- Run independent subagents in parallel
- Faster for multi-step tasks

### 4. Caching
- Cache subagent responses
- Reduce repeated work

---

## Summary

ShowCart's hierarchical agent architecture provides:

âœ… **Intelligent Routing** - Super agent delegates to specialists
âœ… **Context Efficiency** - Isolated subagent contexts
âœ… **User Transparency** - Full execution visible in UI
âœ… **Specialization** - Each agent focuses on domain
âœ… **Scalability** - Easy to add new subagents
âœ… **Type Safety** - End-to-end TypeScript types
âœ… **Cost Optimization** - Right model for each task

The pattern follows AI SDK best practices and enables complex multi-step workflows while maintaining clean, manageable code.

